        self.doc = doc
        self.id = id if id is not None else "_:" + str(_uuid__.uuid4())
        self.format = format
        self.loadContents = loadContents
        self.loadListing = loadListing
        self.default = default
        self.type_ = type_
        self.inputBinding = inputBinding

